      hint: 'ZADD для добавления, ZREVRANGE для топ-N, ZREVRANK для ранга. Pipeline: ZREVRANGE + HGETALL для каждого игрока.',
      solution: '# services.py\nimport redis\nimport json\n\nr = redis.Redis(decode_responses=True)\nLEADERBOARD_KEY = \"game:leaderboard\"\n\ndef add_score(player_id, points, player_name=None):\n    pipe = r.pipeline()\n    pipe.zincrby(LEADERBOARD_KEY, points, player_id)\n    if player_name:\n        pipe.hset(f\"player:{player_id}\", mapping={\n            \"name\": player_name,\n            \"updated_at\": str(timezone.now())\n        })\n    results = pipe.execute()\n    new_score = results[0]\n    rank = r.zrevrank(LEADERBOARD_KEY, player_id)\n    return {\"player\": player_id, \"score\": new_score, \"rank\": rank + 1}\n\ndef get_top(count=10):\n    # Получаем топ-N из Sorted Set\n    top_players = r.zrevrange(LEADERBOARD_KEY, 0, count - 1, withscores=True)\n\n    if not top_players:\n        return []\n\n    # Pipeline для получения профилей\n    pipe = r.pipeline()\n    for player_id, _ in top_players:\n        pipe.hgetall(f\"player:{player_id}\")\n    profiles = pipe.execute()\n\n    result = []\n    for i, (player_id, score) in enumerate(top_players):\n        profile = profiles[i] or {}\n        result.append({\n            \"rank\": i + 1,\n            \"player\": player_id,\n            \"name\": profile.get(\"name\", player_id),\n            \"score\": int(score)\n        })\n    return result\n\ndef get_player_rank(player_id):\n    pipe = r.pipeline()\n    pipe.zrevrank(LEADERBOARD_KEY, player_id)\n    pipe.zscore(LEADERBOARD_KEY, player_id)\n    pipe.hgetall(f\"player:{player_id}\")\n    rank, score, profile = pipe.execute()\n\n    if rank is None:\n        return None\n    return {\n        \"player\": player_id,\n        \"name\": profile.get(\"name\", player_id),\n        \"rank\": rank + 1,\n        \"score\": int(score)\n    }\n\n# views.py\nfrom rest_framework.views import APIView\nfrom rest_framework.response import Response\nfrom . import services\n\nclass ScoreView(APIView):\n    def post(self, request):\n        result = services.add_score(\n            player_id=request.data[\"player\"],\n            points=request.data[\"points\"],\n            player_name=request.data.get(\"name\")\n        )\n        return Response(result)\n\nclass TopView(APIView):\n    def get(self, request):\n        count = int(request.query_params.get(\"count\", 10))\n        return Response(services.get_top(count))\n\nclass RankView(APIView):\n    def get(self, request, player):\n        result = services.get_player_rank(player)\n        if result is None:\n            return Response({\"error\": \"Player not found\"}, status=404)\n        return Response(result)',
